@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2 class="mb-3">Project Board</h2>

@if (_error is not null)
{
    <div class="alert alert-danger">@_error</div>
}
else if (_loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    @* ── Summary stats bar ── *@
    <div class="row g-2 mb-3">
        <div class="col"><div class="card text-center p-2"><strong>Total</strong><span>@FilteredTasks.Count</span></div></div>
        <div class="col"><div class="card text-center p-2"><strong>To Do</strong><span>@TodoTasks.Count</span></div></div>
        <div class="col"><div class="card text-center p-2"><strong>In Progress</strong><span>@InProgressTasks.Count</span></div></div>
        <div class="col"><div class="card text-center p-2"><strong>Done</strong><span>@DoneTasks.Count</span></div></div>
        <div class="col"><div class="card text-center p-2 text-danger"><strong>Overdue</strong><span>@OverdueCount</span></div></div>
    </div>

    @* ── Search bar ── *@
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title…"
               @bind="_searchText" @bind:event="oninput" />
    </div>

    @* ── Kanban columns ── *@
    <div class="row g-3">
        @foreach (var col in Columns)
        {
            var tasks = GetColumnTasks(col.Status);
            <div class="col-md-4">
                <div class="card">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@col.Name</strong>
                        <span class="badge bg-secondary">@tasks.Count</span>
                    </div>
                    <div class="card-body d-flex flex-column gap-2" style="min-height:200px;">
                        @foreach (var task in tasks)
                        {
                            <div class="card shadow-sm">
                                <div class="card-body p-2">
                                    <h6 class="card-title mb-1">@task.Title</h6>
                                    <small class="text-muted">@task.Assignee</small>
                                    <div class="d-flex align-items-center justify-content-between mt-1">
                                        <span class="badge @PriorityClass(task.Priority)">@task.Priority</span>
                                        <small>@task.DueDate.ToString("MMM dd")</small>
                                    </div>
                                    <div class="d-flex justify-content-between mt-2">
                                        @if (col.Index > 0)
                                        {
                                            <button class="btn btn-sm btn-outline-secondary"
                                                    @onclick="() => MoveTask(task.Id, Columns[col.Index - 1].Status)">
                                                ← Move Left
                                            </button>
                                        }
                                        else
                                        {
                                            <span></span>
                                        }
                                        @if (col.Index < Columns.Length - 1)
                                        {
                                            <button class="btn btn-sm btn-outline-secondary"
                                                    @onclick="() => MoveTask(task.Id, Columns[col.Index + 1].Status)">
                                                Move Right →
                                            </button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

                        @* ── Inline add-task form ── *@
                        @if (_addingInColumn == col.Status)
                        {
                            <div class="card border-primary">
                                <div class="card-body p-2 d-flex flex-column gap-2">
                                    <input type="text" class="form-control form-control-sm"
                                           placeholder="Title" @bind="_newTitle" />
                                    <input type="text" class="form-control form-control-sm"
                                           placeholder="Assignee" @bind="_newAssignee" />
                                    <select class="form-select form-select-sm" @bind="_newPriority">
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                    <input type="date" class="form-control form-control-sm" @bind="_newDueDate" />
                                    <div class="d-flex gap-2">
                                        <button class="btn btn-sm btn-primary flex-fill"
                                                @onclick="SaveNewTask" disabled="@_saving">
                                            @(_saving ? "Saving…" : "Save")
                                        </button>
                                        <button class="btn btn-sm btn-outline-secondary flex-fill"
                                                @onclick="CancelAdd" disabled="@_saving">Cancel</button>
                                    </div>
                                </div>
                            </div>
                        }
                        else
                        {
                            <button class="btn btn-sm btn-outline-primary mt-auto"
                                    @onclick="() => StartAdd(col.Status)">+ Add Task</button>
                        }
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private record ColumnDef(string Name, string Status, int Index);

    private static readonly ColumnDef[] Columns =
    [
        new("To Do", "To Do", 0),
        new("In Progress", "In Progress", 1),
        new("Done", "Done", 2)
    ];

    private List<TaskItem> _tasks = [];
    private bool _loading = true;
    private string? _error;
    private string _searchText = string.Empty;

    // Add-task form state
    private string? _addingInColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);
    private bool _saving;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    // Filtered / grouped helpers
    private List<TaskItem> FilteredTasks =>
        string.IsNullOrWhiteSpace(_searchText)
            ? _tasks
            : _tasks.Where(t => t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)).ToList();

    private List<TaskItem> TodoTasks => GetColumnTasks("To Do");
    private List<TaskItem> InProgressTasks => GetColumnTasks("In Progress");
    private List<TaskItem> DoneTasks => GetColumnTasks("Done");
    private int OverdueCount => FilteredTasks.Count(t => t.DueDate.Date < DateTime.Today && t.Status != "Done");

    private List<TaskItem> GetColumnTasks(string status) =>
        FilteredTasks.Where(t => t.Status == status).ToList();

    // Priority badge CSS
    private static string PriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    // Move task between columns
    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = _tasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                _tasks[idx] = _tasks[idx] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            _error = $"Failed to move task: {ex.Message}";
        }
    }

    // Add-task form helpers
    private void StartAdd(string column)
    {
        _addingInColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => _addingInColumn = null;

    private async Task SaveNewTask()
    {
        if (string.IsNullOrWhiteSpace(_newTitle) || _addingInColumn is null) return;

        _saving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
            // The service creates tasks with a default status; update to the target column if needed
            if (created.Status != _addingInColumn)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, _addingInColumn);
                created = created with { Status = _addingInColumn };
            }
            _tasks.Add(created);
            _addingInColumn = null;
        }
        catch (Exception ex)
        {
            _error = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }
}

